function solve(nums, k) {
    const n = nums.length;

    // Helper function to check if an index is a peak given the current array state
    const isPeak = (arr, i) => {
        const prev = arr[(i - 1 + n) % n];
        const next = arr[(i + 1) % n];
        return arr[i] > prev && arr[i] > next;
    };

    // Helper function to count current peaks
    const countPeaks = (arr) => {
        let count = 0;
        for (let i = 0; i < n; i++) {
            if (isPeak(arr, i)) {
                count++;
            }
        }
        return count;
    };

    // Check the theoretical maximum number of peaks.
    // In a circular array, the maximum number of strict peaks is floor(n/2).
    // If n is even, max is n/2. If n is odd, max is (n-1)/2.
    // A more rigorous look: peaks must alternate with valleys. 
